/**
 * Generated by quail.
 *
 * Race-condition baseline for https://www.ing.nl/particulier. When the page exposes a
 * form, asserts the form does not double-submit under a fast
 * double-click — a regression that costs real money on payment /
 * checkout flows and silently inflates contact form noise. Emitted
 * only when probe detected a <form>.
 *
 * Filter: `npx playwright test --grep @kind:race`
 */
import { test, expect } from '@playwright/test'

test.describe.configure({ mode: 'parallel' })
test.describe('ING — race-condition test for https://www.ing.nl/particulier', () => {
  test('double-submit protection: rapid clicks should not cause duplicate submissions', async ({ page }) => {
    await page.goto('/particulier', { waitUntil: 'domcontentloaded' })
    const form = page.locator('form').first()
    if (await form.count() === 0) test.skip()
    const submit = form.locator('button[type="submit"], input[type="submit"]').first()
    if (await submit.count() === 0) test.skip()
    // Fire two clicks back-to-back without waiting for navigation.
    await Promise.allSettled([
      submit.click({ noWaitAfter: true }),
      submit.click({ noWaitAfter: true }),
    ])
    await page.waitForLoadState('domcontentloaded').catch(() => {})
    // Heuristic: only one success message should appear after the race.
    const indicators = page.locator('text=/success|thanks|received|submitted/i')
    const count = await indicators.count()
    expect.soft(count, `${count} success indicators after double-submit — likely a duplicate-submit bug`).toBeLessThanOrEqual(1)
  })
})
